pub fn _3asub(cpu: &mut Cpu) {
    let mut pc: u32 = 0;
    loop {
        match pc {
            0 => {
                cpu.set_y(0x61);  // counter
                pc = 1;
            }
            1 => {
                cpu.set_a(cpu.mem[0x00f2]);
                let _o: u8 = cpu.mem[sym::FrameCount + 1];
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a < cpu.mem[sym::FrameCount + 1] {
                    pc = 4;
                } else {
                    pc = 2;
                }
            }
            2 => {
                if !cpu.flags.z {
                    pc = 8;
                } else {
                    pc = 3;
                }
            }
            3 => {
                cpu.set_a(cpu.mem[0x00f1]);
                let _o: u8 = cpu.mem[sym::FrameCount];
                cpu.flags.c = cpu.reg.a >= _o;
                cpu.flags.z = cpu.reg.a == _o;
                cpu.flags.n = (cpu.reg.a.wrapping_sub(_o) >> 7) != 0;
                if cpu.reg.a >= cpu.mem[sym::FrameCount] {
                    pc = 8;
                } else {
                    pc = 4;
                }
            }
            4 => {
                cpu.set_a(cpu.mem[0x00f1]);
                cpu.flags.c = false;
                pc = 5;
            }
            5 => {
                let _r = (cpu.reg.a as u16) + (0x42) as u16 + (cpu.flags.c as u16);
                cpu.flags.c = (_r >> 8) != 0;
                cpu.set_a(_r as u8);
                cpu.mem[0x00f1] = cpu.reg.a;
                cpu.set_a(cpu.mem[0x00f2]);
                pc = 6;
            }
            6 => {
                let _r = (cpu.reg.a as u16) + (0x04) as u16 + (cpu.flags.c as u16);
                cpu.flags.c = (_r >> 8) != 0;
                cpu.set_a(_r as u8);
                cpu.mem[0x00f2] = cpu.reg.a;
                cpu.flags.d = true;
                cpu.set_a(cpu.reg.y);
                cpu.flags.c = true;
                let _r = (cpu.reg.a as u16) + (!0x01_u8) as u16 + (cpu.flags.c as u16);
                cpu.flags.c = (_r >> 8) != 0;
                cpu.set_a(_r as u8);
                cpu.flags.d = false;
                cpu.set_y(cpu.reg.a);
                if (cpu.reg.y as i8) >= 0 {
                    pc = 1;
                } else {
                    pc = 7;
                }
            }
            7 => {
                cpu.set_y(0x00);
                pc = 8;
            }
            8 => {
                return;
            }
            _ => unreachable!(),
        }
    }
}
